def search_algorithm(src, dsts, G, num_partitions):
    h = G.copy()
    h.remove_edges_from(list(h.in_edges(src)) + list(nx.selfloop_edges(h)))

    # Remove edges with None cost (no cost data available)
    none_cost_edges = [(u, v) for u, v, d in h.edges(data=True) if d.get("cost") is None]
    h.remove_edges_from(none_cost_edges)

    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Build minimum cost Steiner tree using greedy approach
    # The evaluator deduplicates shared edges, so minimizing the tree's total edge cost
    # minimizes broadcast cost.

    # Strategy: Greedy Steiner tree construction
    # 1. Start with src in the tree
    # 2. Repeatedly connect the closest unconnected destination via shortest path
    #    from ANY node already in the tree
    # This exploits relay opportunities through intermediate nodes.

    # Compute shortest paths from src to all nodes
    try:
        src_lengths, src_paths = nx.single_source_dijkstra(h, src, weight="cost")
    except Exception:
        src_lengths, src_paths = {}, {}

    # Also compute shortest paths from all nodes (for relay computation)
    # We need shortest path from any tree node to any remaining destination
    # Start with just paths from src, then expand as we add relay nodes

    tree_nodes = {src}
    tree_edges = []  # list of (u, v) edges in the tree
    remaining_dsts = set(dsts)

    # Cache: shortest path info from each node we've computed
    node_dijkstra = {src: (src_lengths, src_paths)}

    # Greedy: add destinations one at a time, connecting via cheapest path from tree
    while remaining_dsts:
        best_cost = float('inf')
        best_dst = None
        best_path = None
        best_from = None

        for tree_node in list(tree_nodes):
            if tree_node not in node_dijkstra:
                try:
                    lengths, paths = nx.single_source_dijkstra(h, tree_node, weight="cost")
                    node_dijkstra[tree_node] = (lengths, paths)
                except Exception:
                    node_dijkstra[tree_node] = ({}, {})

            lengths, paths = node_dijkstra[tree_node]

            for dst in remaining_dsts:
                if dst in lengths:
                    # Cost to connect dst from this tree_node
                    # But we need to account for the path from src to tree_node
                    # actually no - tree_node is already in the tree, so its cost is already paid
                    # We just need the incremental cost of the new edges
                    path = paths[dst]
                    # Calculate incremental cost: only count edges NOT already in tree
                    incremental_cost = 0
                    for i in range(len(path) - 1):
                        edge = (path[i], path[i+1])
                        if edge not in set(tree_edges):
                            incremental_cost += h[path[i]][path[i+1]]["cost"]

