    try:
        src_lengths, src_paths = nx.single_source_dijkstra(h, src, weight="cost")
    except Exception:
        src_lengths, src_paths = {}, {}

    # Baseline: union of direct shortest paths (edges deduplicated)
    baseline_edges = set()
    baseline_valid = True
    for dst in dsts:
        if dst not in src_paths:
            baseline_valid = False
            break
        path = src_paths[dst]
        for i in range(len(path) - 1):
