                        for k in range(len(p) - 1):
                            tree_edges.add((p[k], p[k+1]))
                    for d in remaining_dsts:
                        best_d_path = None
                        best_d_inc = float('inf')
                        for hx_data in [(hub1, hub_data[hub1]), (hub2, hub_data[hub2])]:
                            hxl, hxp = hx_data[1]
                            if d in hxl:
                                dp = hxp[d]
                                inc = sum(h[dp[k]][dp[k+1]]["cost"] for k in range(len(dp)-1) if (dp[k], dp[k+1]) not in tree_edges)
                                if inc < best_d_inc:
                                    best_d_inc = inc
                                    best_d_path = dp
