                        best_tree_edges = tree_edges

    # Build final topology
    steiner_tree = nx.DiGraph()
    for u, v in best_tree_edges:
        steiner_tree.add_edge(u, v, cost=h[u][v]["cost"])

    for dst in dsts:
        try:
            tree_path = nx.shortest_path(steiner_tree, src, dst)
            for i in range(len(tree_path) - 1):
                s, t = tree_path[i], tree_path[i+1]
